import { useEffect, useState } from 'react';
import { NavLink, useLocation } from 'react-router-dom';

const links = [
  { to: '/', label: 'Home' }, { to: '/about', label: 'About' }, { to: '/initiatives', label: 'Initiatives' }, { to: '/events', label: 'Events' },
  { to: '/gallery', label: 'Gallery' }, { to: '/blog', label: 'Blog' }, { to: '/volunteer', label: 'Volunteer' }, { to: '/contact', label: 'Contact' }
];

export default function Navbar() {
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();
  useEffect(() => setOpen(false), [location.pathname]);
  useEffect(() => { const update = () => setScrolled(window.scrollY > 28); update(); window.addEventListener('scroll', update); return () => window.removeEventListener('scroll', update); }, []);
  return <header className={`navbar ${scrolled || location.pathname !== '/' ? 'navbar-solid' : 'navbar-overlay'}`}>
    <NavLink to="/" className="brand"><span className="brand-mark">A</span><span>ARISE <b>'20</b><small>FOUNDATION</small></span></NavLink>
    <nav className={`nav-links ${open ? 'is-open' : ''}`} aria-label="Main navigation">{links.map((link) => <NavLink key={link.to} to={link.to} className={({ isActive }) => isActive ? 'active' : ''}>{link.label}</NavLink>)}</nav>
    <NavLink to="/donate" className="donate-btn">Donate Now <span>→</span></NavLink>
    <button className="mobile-menu" aria-label="Toggle navigation" aria-expanded={open} onClick={() => setOpen(!open)}>{open ? '×' : '☰'}</button>
  </header>;
}
